"""
Sales Analysis Engine using MongoDB aggregation pipelines.
Identifies top-performing products within a date range, grouped by category.
"""

from pymongo import MongoClient
from pymongo.errors import ConnectionError, OperationError
from datetime import datetime
from typing import Dict, List, Any


class SalesAnalyzer:
    """
    A robust sales analysis engine using MongoDB aggregation pipelines.

    This class analyzes sales data to identify top-performing products
    within a specific date range, grouped by category.
    """

    def __init__(self, db_url: str, db_name: str) -> None:
        """
        Initialize the SalesAnalyzer with database connection parameters.

        Args:
            db_url: MongoDB connection URL (e.g., "mongodb://localhost:27017")
            db_name: Name of the database to analyze

        Raises:
            ConnectionError: If unable to connect to the MongoDB instance
        """
        try:
            self.client: MongoClient = MongoClient(db_url)
            self.db = self.client[db_name]
            # Verify connection
            self.client.admin.command('ping')
        except ConnectionError as e:
            raise ConnectionError(f"Failed to connect to MongoDB at {db_url}: {e}")

    def get_top_performing_products(
        self, 
        start_date: str, 
        end_date: str, 
        limit: int = 3
    ) -> Dict[str, List[Dict[str, Any]]]:
        """
        Identify top-performing products within a date range, grouped by category.

        Performance is measured by total revenue (price * quantity). Products
        are ranked within each category by:
        1. Total Revenue (Descending)
        2. Total Quantity (Descending)
        3. Product ID (Ascending) - for deterministic tie-breaking

        Args:
            start_date: ISO 8601 formatted start date (inclusive)
                       e.g., "2024-10-01T00:00:00"
            end_date: ISO 8601 formatted end date (inclusive)
                     e.g., "2024-12-31T23:59:59"
            limit: Number of top products to retrieve per category (default: 3)

        Returns:
            Dictionary where:
            - Keys: Category names (str)
            - Values: Lists of product dictionaries containing:
                - product_id: int
                - product_name: str
                - total_revenue: float (rounded to 2 decimal places)
                - total_quantity: int

        Returns empty dict if no matching orders found.
        """
        try:
            # Parse ISO 8601 dates
            start_datetime = datetime.fromisoformat(start_date.replace('Z', '+00:00'))
            end_datetime = datetime.fromisoformat(end_date.replace('Z', '+00:00'))
        except (ValueError, AttributeError) as e:
            raise ValueError(f"Invalid ISO 8601 date format: {e}")

        # Access collections
        orders_collection = self.db['orders']
        products_collection = self.db['products']

        # Build the aggregation pipeline
        pipeline: List[Dict[str, Any]] = [
            # Stage 1: Filter orders within the date range (inclusive)
            {
                '$match': {
                    'order_date': {
                        '$gte': start_datetime,
                        '$lte': end_datetime
                    }
                }
            },
            # Stage 2: Lookup product information
            {
                '$lookup': {
                    'from': 'products',
                    'localField': 'product_id',
                    'foreignField': 'product_id',
                    'as': 'product_info'
                }
            },
            # Stage 3: Unwind product_info to filter out orphaned orders
            {
                '$unwind': {
                    'path': '$product_info',
                    'preserveNullAndEmptyArrays': False
                }
            },
            # Stage 4: Calculate revenue for each order (price * quantity)
            {
                '$addFields': {
                    'order_revenue': {
                        '$multiply': [
                            '$product_info.price',
                            '$quantity'
                        ]
                    }
                }
            },
            # Stage 5: Group by product and calculate aggregates
            {
                '$group': {
                    '_id': {
                        'product_id': '$product_id',
                        'product_name': '$product_info.product_name',
                        'category': '$product_info.category'
                    },
                    'total_revenue': {
                        '$sum': '$order_revenue'
                    },
                    'total_quantity': {
                        '$sum': '$quantity'
                    }
                }
            },
            # Stage 6: Reshape document structure for easier processing
            {
                '$project': {
                    '_id': 0,
                    'product_id': '$_id.product_id',
                    'product_name': '$_id.product_name',
                    'category': '$_id.category',
                    'total_revenue': {
                        '$round': ['$total_revenue', 2]
                    },
                    'total_quantity': '$total_quantity'
                }
            },
            # Stage 7: Sort by category, then by ranking criteria
            {
                '$sort': {
                    'category': 1,
                    'total_revenue': -1,
                    'total_quantity': -1,
                    'product_id': 1
                }
            },
            # Stage 8: Group by category and limit top products
            {
                '$group': {
                    '_id': '$category',
                    'products': {
                        '$push': {
                            'product_id': '$product_id',
                            'product_name': '$product_name',
                            'total_revenue': '$total_revenue',
                            'total_quantity': '$total_quantity'
                        }
                    }
                }
            },
            # Stage 9: Slice top products per category
            {
                '$project': {
                    '_id': 0,
                    'category': '$_id',
                    'products': {
                        '$slice': ['$products', limit]
                    }
                }
            },
            # Stage 10: Sort categories alphabetically for consistent output
            {
                '$sort': {
                    'category': 1
                }
            }
        ]

        # Execute the aggregation pipeline
        try:
            results = list(orders_collection.aggregate(pipeline))
        except OperationError as e:
            raise OperationError(f"Aggregation pipeline failed: {e}")

        # Transform results into the required dictionary format
        output: Dict[str, List[Dict[str, Any]]] = {}
        for result in results:
            category = result['category']
            products = result['products']
            output[category] = products

        return output

    def close(self) -> None:
        """Close the MongoDB client connection."""
        if self.client:
            self.client.close()

    def __del__(self) -> None:
        """Ensure connection is closed when object is destroyed."""
        try:
            self.close()
        except Exception:
            pass

